  "solutions.hero.status1": "<span>Importadores y mayoristas</span><span class=\"hero-status-value\">Puerto a bodega</span>",
  "solutions.hero.status2": "<span>Distribuidores</span><span class=\"hero-status-value is-accent\">Bodega a ruta</span>",
  "solutions.hero.status3": "<span>Operadores de camaras frias</span><span class=\"hero-status-value\">Monitoreo de instalacion</span>",
  "solutions.routing.badge": "Ruteo operativo",
  "solutions.routing.title": "Empieza por el nodo donde el control se rompe primero.",
  "solutions.routing.copy": "En lugar de navegar tarjetas de funciones, entra por el traspaso fisico que necesitas estabilizar primero: llegada, despacho o monitoreo de camara de queso.",
  "solutions.route.importers": `<div class="solution-route-meta">Puerto a bodega</div><h2 class="solution-route-title">Importadores y mayoristas</h2><p class="solution-route-copy">Modela la condicion del contenedor antes de recepcionar, mapea lotes de queso y lacteos al llegar y separa carga comprometida antes de que entre al inventario vendible.</p><ul class="solution-route-list"><li>Flujo de contenedor desde origen hasta bodega</li><li>Monitoreo termico marcado como roadmap</li><li>Mapeo de inventario a granel</li></ul><a href="importers.html" class="solution-route-cta">Explorar para importadores</a>`,
  "solutions.route.distributors": `<div class="solution-route-meta">Bodega a ruta</div><h2 class="solution-route-title">Distribuidores</h2><p class="solution-route-copy">Reemplaza pedidos por WhatsApp con un flujo demo desde el ingreso B2B hasta el despacho FEFO y la prueba firmada de entrega.</p><ul class="solution-route-list"><li>Portal B2B de autoservicio</li><li>FEFO por lote</li><li>POD digital con temperatura de entrega</li></ul><a href="distributors.html" class="solution-route-cta">Explorar para distribuidores</a>`,
  "solutions.route.storage": `<div class="solution-route-meta">Monitoreo de instalacion</div><h2 class="solution-route-title">Operadores de camaras frias</h2><p class="solution-route-copy">Unifica registros de camaras, escalamiento y salidas de auditoria para que el cumplimiento ya no viva en hojas sueltas ni en exports USB.</p><ul class="solution-route-list"><li>Panel multicamara planificado</li><li>Reportes de cumplimiento como roadmap</li><li>Despacho de alertas en fase posterior</li></ul><a href="cold-storage.html" class="solution-route-cta">Explorar para camaras frias</a>`,
  "solutions.advantage.badge": "Infraestructura compartida",
  "solutions.advantage.title": "Por que los operadores eligen Nexa en lugar de construir por su cuenta.",
