  "solutions.advantage.card1": `<div class="advantage-icon" aria-hidden="true"><svg viewBox="0 0 24 24" fill="none" stroke="currentColor" stroke-width="2" stroke-linecap="round" stroke-linejoin="round"><circle cx="12" cy="12" r="10"></circle><polyline points="12 6 12 12 16 14"></polyline></svg></div><h3>Operational demo in days</h3><p>The MVP shows inventory and orders with demo data. Real integrations are planned by phase.</p>`,
